const items = $input.all();
if (!items || items.length === 0) return [];

console.log(`Cards recebidos: ${items.length}`);

// Data de hoje em BRT (UTC-3) — zerando a hora para comparar só o DIA
const agoraUTC = new Date();
const agoraBRT = new Date(agoraUTC.getTime() - 3 * 60 * 60 * 1000);

// Meia-noite de hoje em BRT (como referência de dia)
const hojeBRT = new Date(Date.UTC(
  agoraBRT.getUTCFullYear(),
  agoraBRT.getUTCMonth(),
  agoraBRT.getUTCDate(),
  0, 0, 0
));

console.log(`Hoje BRT (meia-noite): ${hojeBRT.toISOString()}`);

const resultado = [];

for (const item of items) {
  const card = item.json;
  if (!card.due_date || !card.titulo) continue;

  // Parsear due_date de forma robusta
  const dueDateStr = String(card.due_date)
    .replace('+00:00', 'Z')
    .replace(' ', 'T');
  const dueDateUTC = new Date(dueDateStr);

  if (isNaN(dueDateUTC.getTime())) {
    console.log(`Data inválida: ${card.due_date}`);
    continue;
  }

  // Converter due_date para BRT e pegar só o DIA
  const dueBRT = new Date(dueDateUTC.getTime() - 3 * 60 * 60 * 1000);
  const dueDiaBRT = new Date(Date.UTC(
    dueBRT.getUTCFullYear(),
    dueBRT.getUTCMonth(),
    dueBRT.getUTCDate(),
    0, 0, 0
  ));

  // Diferença em DIAS (comparando dias corridos, não horas exatas)
  const diffDias = Math.round((dueDiaBRT - hojeBRT) / (1000 * 60 * 60 * 24));

  const horaFormatada = `${String(dueBRT.getUTCHours()).padStart(2,'0')}:${String(dueBRT.getUTCMinutes()).padStart(2,'0')}`;

  console.log(`[${card.titulo.substring(0,40)}] due_dia=${dueDiaBRT.toISOString().slice(0,10)} diffDias=${diffDias} hora=${horaFormatada}`);

  // Lógica por DIA CORRIDO
  const is2dias = diffDias === 2;
  const is1dia  = diffDias === 1;
  // Para HOJE: só notifica se o leilão ainda NÃO aconteceu
  // Tolerância de 30min após o horário (workflow pode rodar até 30min depois)
  const isHoje  = diffDias === 0 && dueDateUTC.getTime() > (agoraUTC.getTime() - 30 * 60 * 1000);

  if (!isHoje && !is1dia && !is2dias) {
    console.log(`  → fora das janelas (${diffDias} dias), pulando`);
    continue;
  }

  // Formatar data
  const dataFormatada = dueDiaBRT.toLocaleDateString('pt-BR', {
    timeZone: 'UTC',
    weekday: 'long',
    day: '2-digit',
    month: 'long',
    year: 'numeric'
  });

  const tituloResumido = card.titulo.length > 120
    ? card.titulo.substring(0, 120) + '...'
    : card.titulo;

  let tipoLembrete, emoji, urgencia;
  if (isHoje) {
    tipoLembrete = 'HOJE';
    emoji = '🔨';
    urgencia = 'LEILÃO HOJE! Acesse o link agora.';
  } else if (is1dia) {
    tipoLembrete = '1 DIA';
    emoji = '⚠️';
    urgencia = 'AMANHÃ! Confirme sua participação.';
  } else {
    tipoLembrete = '2 DIAS';
    emoji = '📅';
    urgencia = 'Prepare documentação e análise jurídica!';
  }

  const linhas = [
    `${emoji} *LEMBRETE DE LEILÃO — FALTAM ${tipoLembrete}*`,
    ``,
    `🏠 *Imóvel:*`,
    tituloResumido,
    ``,
    `📆 *Data:* ${dataFormatada}`,
    `🕐 *Horário:* ${horaFormatada}`,
    ``,
    `⚡ ${urgencia}`,
  ];

  if (card.link_leilao) {
    linhas.push(``);
    linhas.push(`🔗 *Link do leilão:*`);
    linhas.push(card.link_leilao);
  }

  linhas.push(``);
  linhas.push(`_FlowDesck · Ruah Systems_`);

  resultado.push({
    json: {
      id: card.id,
      titulo: card.titulo,
      due_date: card.due_date,
      link_leilao: card.link_leilao || '',
      mensagem: linhas.join('\n'),
      tipoLembrete,
      dataFormatada,
      horaFormatada,
      tituloResumido,
      diffDias
    }
  });

  console.log(`  ✅ Lembrete ${tipoLembrete} gerado!`);
}

console.log(`Total lembretes: ${resultado.length}`);
return resultado;
